// Validate incoming evidence request
const { phase_name, phase_output, success_criteria, client_id, request_id } = $input.first().json.body;

if (!phase_name || !phase_output || !success_criteria) {
  throw new Error('Missing required: phase_name, phase_output, success_criteria');
}

const validation_id = `audit-${request_id || phase_name}-${Date.now()}`;

return [{
  json: {
    validation_id,
    phase_name,
    phase_output: phase_output.slice(0, 5000),
    success_criteria,
    client_id: client_id || 'unknown',
    request_id: request_id || 'unknown',
    received_at: new Date().toISOString()
  }
}];

// Sprint 8 · CC#2 · 2026-05-24 · structural validation · lenient JSON parse.
// On non-JSON phase_output (prose / markdown narrative) gracefully degrades ·
// skips required-fields check + lets downstream Semantic Validation + Extract
// Verdict route via severity. Matches Camino A canon (adapters never throw ·
// chain surfaces verdicts instead of dying mid-execution).
const phase_requirements = {
  'DISCOVER': ['market_opportunity', 'competitive_landscape', 'client_objectives'],
  'STRATEGIZE': ['positioning', 'messaging_pillars', 'channel_mix', 'budget'],
  'SCAFFOLD': ['content_calendar', 'creative_briefs', 'platform_requirements'],
  'BUILD': ['creative_assets', 'seo_optimization', 'paid_media_setup'],
  'HARDEN': ['qa_results', 'ab_tests_config', 'compliance_validation'],
  'LAUNCH': ['audiences_targeted', 'campaigns_live', 'budget_deployed'],
  'OPERATE': ['performance_metrics', 'optimization_recommendations', 'team_briefing']
};

const raw = $json.phase_output;
const structural_issues = [];
let output_format = 'json';
let output = null;

if (raw === null || raw === undefined || raw === '') {
  output_format = 'empty';
  structural_issues.push('phase_output is empty');
} else if (typeof raw === 'object') {
  output = raw; // already parsed
} else if (typeof raw === 'string') {
  try {
    output = JSON.parse(raw);
  } catch {
    output_format = raw.trim().startsWith('#') || raw.includes('\n## ') ? 'markdown' : 'prose';
    structural_issues.push(`phase_output not JSON (${output_format}) · per-phase field check skipped · downstream semantic validation applies`);
  }
} else {
  output_format = `unknown (${typeof raw})`;
  structural_issues.push(`phase_output unexpected type · ${typeof raw}`);
}

// Per-phase field check only when output parsed as object
if (output && typeof output === 'object' && !Array.isArray(output)) {
  const required = phase_requirements[$json.phase_name] || [];
  required.forEach((field) => {
    if (!(field in output) || !output[field]) {
      structural_issues.push(`Missing required field: ${field}`);
    }
  });
}

const criteria = Array.isArray($json.success_criteria)
  ? $json.success_criteria
  : (typeof $json.success_criteria === 'string' ? $json.success_criteria.split(',') : []);

return [{
  json: {
    validation_id: $json.validation_id,
    phase_name: $json.phase_name,
    structural_valid: structural_issues.length === 0,
    structural_issues,
    output_format,
    phase_output: $json.phase_output,
    success_criteria: criteria,
  }
}];

// Extract validation verdict
const editor_response = $node['Semantic Validation (Editor en Jefe QC)'].json;

let verdict = 'PASS';
let severity = 'low';
let issues = [];

if (editor_response.success === false) {
  verdict = 'FAIL';
  severity = 'critical';
  issues = [editor_response.error || 'Editor validation failed'];
} else {
  verdict = editor_response.verdict || 'PASS';
  severity = editor_response.severity || 'low';
  issues = editor_response.issues || [];
}

return [{
  json: {
    validation_id: $json.validation_id,
    phase_name: $json.phase_name,
    verdict,
    severity,
    structural_issues: $json.structural_issues || [],
    semantic_issues: issues,
    editor_rationale: editor_response.rationale || '',
    all_issues_count: ($json.structural_issues || []).length + issues.length,
    validated_at: new Date().toISOString()
  }
}];

// Camino A · 2026-05-23 · CC#2
// 1) Wrap executeWorkflow flat input into webhook-equivalent shape (.body)
// 2) Map NEXUS-internal key aliases to Phase-Gate-canonical names
//    (phase → phase_name · output → phase_output) so downstream
//    Normalize Request destructure works without code edits.
const p = $input.first().json;
const body = {
  ...p,
  phase_name: p.phase_name ?? p.phase ?? p.current_phase,
  phase_output: p.phase_output ?? p.output ?? p.result,
  success_criteria: Array.isArray(p.success_criteria) && p.success_criteria.length === 0
    ? ['(none provided · default)']
    : (p.success_criteria ?? ['(none provided · default)'])
};
return [{ json: { body } }];
